root.js-content:
stp.writeLog("Start: IWGT Amended function");
stp.setAutoProcess(true);

stp.setCmpId(stp.getMsgTagVal("CustId"));
stp.setUserId("CSBANK");

var sAdvNb = stp.getMsgTagVal("AdvNb");
var arrKeys = [["ADV_NO",sAdvNb]];
var arrGetDataResult = stp.SYS_getCUBKVal("GetParentRef",arrKeys);
var sParentRef = arrGetDataResult[0];
stp.updateFieldValue("PARENT_MAIN_REF",sParentRef);

stp.updateFieldValue("TEMP_EXPIRY_DT", stp.getFieldValue("EXPIRY_DT"));
stp.updateFieldValue("TEMP_EXPIRY_COND", stp.getFieldValue("EXPIRY_COND"));
var NEW_EXPIRY_TYPE = stp.getFieldValue("NEW_EXPIRY_TYPE");
		if(NEW_EXPIRY_TYPE != ''){
          if(NEW_EXPIRY_TYPE == 'COND') {
                stp.updateFieldValue("TEMP_EXPIRY_COND", stp.getFieldValue("NEW_EXPIRY_COND"));
				stp.updateFieldValue("TEMP_EXPIRY_DT", stp.getFieldValue("NEW_EXPIRY_DT"));
          }else if(NEW_EXPIRY_TYPE == 'FIXD'){
                stp.updateFieldValue("TEMP_EXPIRY_DT", stp.getFieldValue("NEW_EXPIRY_DT"));
                stp.updateFieldValue("TEMP_EXPIRY_COND", "");
          }else if(NEW_EXPIRY_TYPE == 'OPEN'){
                stp.updateFieldValue("TEMP_EXPIRY_DT", "");
                stp.updateFieldValue("TEMP_EXPIRY_COND", "");
        } 
	  }	else{
		  var EXPIRY_DT = stp.getFieldValue("EXPIRY_DT");
		  var EXPIRY_COND = stp.getFieldValue("EXPIRY_COND");
		  var NEW_EXPIRY_DT = stp.getFieldValue("NEW_EXPIRY_DT");
		  var NEW_EXPIRY_COND = stp.getFieldValue("NEW_EXPIRY_COND");
		  if(NEW_EXPIRY_DT.length > 0){
			  stp.updateFieldValue("TEMP_EXPIRY_DT", stp.getFieldValue("NEW_EXPIRY_DT"));
		  }
		  if(EXPIRY_COND != '' && NEW_EXPIRY_COND != ''){
			  stp.updateFieldValue("TEMP_EXPIRY_COND", stp.getFieldValue("NEW_EXPIRY_COND"));
		  }
	  }	

stp.execInqAttribute();
stp.writeLog("End: IWGT Amended function");
stp.updateFieldValue("CURRNT_STATUS","Amended");
stp.writeLog("Start: Get Email Senders List");
var sEmailTrxType = "N";
var sFuncId = "F05030700923";
var arrKeys = [["EMAILTRX_TYPE",sEmailTrxType]];
var arrGetDataResult = stp.SYS_getCUBKVal("InqEmailGrpArray",arrKeys);
if (arrGetDataResult){
    var sEmailArray = arrGetDataResult[0];
    var sEmailGrpNm = "";
    var eList = sEmailArray.split("/");
    for (k=0;k<eList.length;k++) {
	var fList = eList[k].split("-");
         if (fList[0]==sFuncId) {
	    sEmailGrpNm = fList[1];
         }
    }  	      
    if (sEmailGrpNm.length() > 0){
        var arrKeysforEmailList = [["EMAILGRP_NM",sEmailGrpNm]];
        var arrGetDataResultforEmailList = stp.SYS_getCUBKVal("InqEmailList",arrKeysforEmailList);
        var sEmailListArray = arrGetDataResultforEmailList[0]; 	    
        stp.updateFieldValue("EMAIL_TO",sEmailListArray);
        stp.updateFieldValue("EMAIL_SUBJECT","CSBank Email Notification"); 
    }
}
stp.writeLog("End: Get Email Senders List");
